-- Migration 155: move 'Certification Exam at Pearson Vue' section out of
-- short_description and into the per-course course_<sku>_certification
-- cms_block for every AWS course that carries it. AWS analogue of the
-- CompTIA move done by migration 151.
--
-- Mirrors what scripts/local-dev/move-aws-pearson-vue-to-block.php already
-- did on local. Backup payloads come from
-- media/migrations-reports/move-aws-pearson-vue-apply-20260525-044053.json
-- (29 products). Final cms_block content is read live from this DB (which
-- is the post-move state, identical to the target prod state).
--
-- Idempotency: REPLACE() no-ops on stripped rows; cms_block UPDATE writes
-- the final content unconditionally (already-final rows just overwrite
-- themselves with the same value).

-- C19 (entity_id=19)
UPDATE catalog_product_entity_text SET value = REPLACE(value, '<h2>Certification Exam at Pearson Vue</h2>\r\n<p>Once you are prepared for the exam, you can register for the certification&nbsp;<a href=\"https://aws.amazon.com/certification/certified-ai-practitioner/\" title=\"AWS Certified AI Practitioner\" target=\"_blank\"><span style=\"text-decoration: underline;\">AIF-C01 AWS Certified AI Practitioner Exam here</span></a>. We are Authorised Pearson Vue Testing Center. You can take the certification exam at our test center.&nbsp;Note that the course fee does not include the certification exam fee.</p>\r\n<p><span>You can purchase the exam voucher (one of the lowest prices in Singapore) at&nbsp;</span><span><span style=\"text-decoration: underline;\"><a href=\"https://www.tertiarycourses.com.sg/aws-foundational-certification-exam-vouchers.html\" title=\"AWS Foundational Certification Exam Voucher\" target=\"_blank\">AWS Foundational Certification Exam Voucher</a></span>.<br /></span></p>\r\n', '') WHERE entity_id = 19 AND attribute_id = 73;
UPDATE cms_block SET content = '<ul>\r\n<li>\r\n<p><strong>Certificate of Completion from Tertiary Infotech</strong>&nbsp;- Upon meeting at least 75% attendance and passing the assessment(s), participants will receive a Certificate of Completion from Tertiary Infotech.</p>\r\n</li>\r\n<li><strong>External Certification</strong> - The participant will be able to attempt the AWS Certified AI Practitioner exam after attending this course. Upon passing the exam, you will receive the AWS Certified AI Practitioner accreditation. This certification validates that the individual possesses the skills and knowledge necessary to design and deploy scalable, highly available, and fault-tolerant systems on the Amazon Web Services (AWS) platform. It demonstrates proficiency in various aspects of AWS architecture, including designing and deploying applications on AWS, selecting appropriate AWS services based on requirements, designing highly available and scalable systems, and implementing cost-effective solutions.</li>\r\n</ul>\n<p><strong>Certification Exam at Pearson Vue</strong></p>\n<p>Once you are prepared for the exam, you can register for the certification&nbsp;<a href=\"https://aws.amazon.com/certification/certified-ai-practitioner/\" title=\"AWS Certified AI Practitioner\" target=\"_blank\"><span style=\"text-decoration: underline;\">AIF-C01 AWS Certified AI Practitioner Exam here</span></a>. We are Authorised Pearson Vue Testing Center. You can take the certification exam at our test center.&nbsp;Note that the course fee does not include the certification exam fee.</p>\r\n<p><span>You can purchase the exam voucher (one of the lowest prices in Singapore) at&nbsp;</span><span><span style=\"text-decoration: underline;\"><a href=\"https://www.tertiarycourses.com.sg/aws-foundational-certification-exam-vouchers.html\" title=\"AWS Foundational Certification Exam Voucher\" target=\"_blank\">AWS Foundational Certification Exam Voucher</a></span>.<br /></span></p>', update_time = NOW() WHERE identifier = 'course_C19_certification';
