UPDATE catalog_product_entity_text SET value = REPLACE(value, '<h2>Certification Exam at Pearson Vue</h2>\r\n<p>Once you are prepared for the exam, you can register for the <a href=\"https://aws.amazon.com/certification/certified-cloud-practitioner/\" title=\"AWS Certified Cloud Practitioner\" target=\"_blank\"><span style=\"text-decoration: underline;\">CLF-C02 AWS Certified Cloud Practitioner Exam here</span></a>. We are Authorised Pearson Vue Testing Center. You can take the certification exam at our test center.&nbsp;Note that the course fee does not include the certification exam fee.</p>\r\n<p>You can purchase the exam voucher (one of the lowest prices in Singapore) at&nbsp;<span style=\"text-decoration: underline;\"><a href=\"https://www.tertiarycourses.com.sg/aws-foundational-certification-exam-vouchers.html\" title=\"AWS Foundational Certification Exam Voucher\" target=\"_blank\">AWS Foundational Certification Exam Voucher</a></span></p>\r\n', '') WHERE entity_id = 617 AND attribute_id = 73;
UPDATE cms_block SET content = '<ul>\r\n<li>\r\n<p><strong>Certificate of Completion from Tertiary Infotech</strong> - Upon meeting at least 75% attendance and passing the assessment(s), participants will receive a Certificate of Completion from Tertiary Infotech.</p>\r\n</li>\r\n<li>\r\n<p><strong>OpenCerts from SkillsFuture Singapore</strong> - After passing the assessment(s) and achieving at least 75% attendance, participants will receive a OpenCert (aka Statement of Achievement) from SkillsFuture Singapore, certifying that they have&nbsp;achieved the Competency Standard(s) in the above Skills Framework.</p>\r\n</li>\r\n<li><strong>External Certification</strong> -&nbsp;The participant will be able to attempt the AWS Certified Cloud Practitioner exam after attending this course. Upon passing the exam, you will receive the AWS Certified Cloud Practitioner accreditation. This certification validates foundational knowledge of AWS Cloud essentials, including concepts, services, security, architecture, pricing, and support. It serves as an entry-level certification for those starting in cloud computing or seeking to validate their understanding of AWS Cloud services and solutions.</li>\r\n</ul>\n<p><strong>Certification Exam at Pearson Vue</strong></p>\n<p>Once you are prepared for the exam, you can register for the <a href=\"https://aws.amazon.com/certification/certified-cloud-practitioner/\" title=\"AWS Certified Cloud Practitioner\" target=\"_blank\"><span style=\"text-decoration: underline;\">CLF-C02 AWS Certified Cloud Practitioner Exam here</span></a>. We are Authorised Pearson Vue Testing Center. You can take the certification exam at our test center.&nbsp;Note that the course fee does not include the certification exam fee.</p>\r\n<p>You can purchase the exam voucher (one of the lowest prices in Singapore) at&nbsp;<span style=\"text-decoration: underline;\"><a href=\"https://www.tertiarycourses.com.sg/aws-foundational-certification-exam-vouchers.html\" title=\"AWS Foundational Certification Exam Voucher\" target=\"_blank\">AWS Foundational Certification Exam Voucher</a></span></p>', update_time = NOW() WHERE identifier = 'course_TGS-2023039183_certification';
