le=\"text-decoration: underline;\"><a href=\"https://www.tertiarycourses.com.sg/aws-foundational-certification-exam-vouchers.html\" title=\"AWS Foundational Certification Exam Voucher\" target=\"_blank\">AWS Foundational Certification Exam Voucher</a></span></p>', 1, NOW(), NOW() FROM DUAL WHERE NOT EXISTS (SELECT 1 FROM cms_block c WHERE c.identifier = 'course_TGS-2023039183_certification');
