UPDATE cms_block SET content = '<ul>\r\n<li>\r\n<p><strong>Certificate of Completion from Tertiary Infotech</strong>&nbsp;- Upon meeting at least 75% attendance and passing the assessment(s), participants will receive a Certificate of Completion from Tertiary Infotech.</p>\r\n</li>\r\n<li><strong>External Certification</strong>&nbsp;-&nbsp;The participant will be able to attempt the AWS Certified Advanced Networking Specialty (ANS-C01) exam after attending this course. Upon passing the exam, you will receive the&nbsp;AWS Certified Advanced Networking Specialty (ANS-C01)&nbsp;accreditation. This certification validates that the individual possesses the skills and knowledge necessary to design and deploy scalable, highly available, and fault-tolerant systems on the Amazon Web Services (AWS) platform. It demonstrates proficiency in various aspects of AWS architecture, including designing and deploying applications on AWS, selecting appropriate AWS services based on requirements, designing highly available and scalable systems, and implementing cost-effective solutions.</li>\r\n</ul>\n<p><strong>Certification Exam at Pearson Vue</strong></p>\n<p>Once you are prepared for the exam, you can register for the<span>&nbsp;</span><span><a href=\"https://aws.amazon.com/certification/certified-solutions-architect-associate/\" title=\"SAA-C03 AWS Certified Solutions Architect - Associate\" target=\"_blank\">SAA-C03 AWS Certified Solutions Architect Exam here</a></span>.&nbsp;We are Authorised Pearson Vue Testing Center. You can take the certification exam at our test center.&nbsp;Note that the course fee does not include the certification exam fee.</p>\r\n<p>You can purchase the exam voucher (one of the lowest prices in Malaysia) at&nbsp;<span><a href=\"https://www.tertiarycourses.com.my/aws-assoicate-certification-exam-vouchers-malaysia.html\" title=\"AWS Associate Certification Exam Voucher\" target=\"_blank\">AWS Associate Certification Exam Voucher</a>.</span></p>\r\n<p></p>\r\n<p></p>', update_time = NOW() WHERE identifier = 'course_M1328_certification';
