erline;\"><a href=\"https://www.tertiarycourses.com.sg/aws-foundational-certification-exam-vouchers.html\" title=\"AWS Foundational Certification Exam Voucher\" target=\"_blank\">AWS Foundational Certification Exam Voucher</a></span>.</p>', update_time = NOW() WHERE identifier = 'course_TGS-2025054815_certification';
